// App.jsx
import { Routes, Route, Navigate } from "react-router-dom";
import { useState } from "react";

// Pages
import Register from "./pages/Auth/Register";
import Login from "./pages/Auth/Login";
import Dashboard from "./pages/Dashboard/Dashboard"; // untuk Admin
import DashboardSuperAdmin from "./pages/Dashboard/DashboardSuperAdmin"; // untuk Super Admin
import MasterData from "./pages/MasterData/MasterData"; // hanya Admin
import Tracking from "./pages/Tracking/Tracking"; // Admin & Super Admin
import InfoDriver from "./pages/InfoDriver/InfoDriver"; // Admin & Super Admin
import ByPass from "./pages/ByPass/ByPass"; // hanya Super Admin
import Settings from "./pages/Settings/Settings"; // Admin & Super Admin
import Logout from "./pages/Auth/Logout"; // Logout

export default function App() {
  const [userRole, setUserRole] = useState(null);
  const isLoggedIn = !!userRole;

  /**
   * Fungsi proteksi akses berdasarkan role
   * @param {JSX.Element} element Komponen halaman
   * @param {Array} allowedRoles Daftar role yang diizinkan
   */
  const protectedRoute = (element, allowedRoles) => {
    if (!isLoggedIn) return <Navigate to="/login" />;
    if (!allowedRoles.includes(userRole)) return <Navigate to="/dashboard" />;
    return element;
  };

  return (
    <Routes>
      {/* Public Routes */}
      <Route path="/register" element={<Register />} />
      <Route path="/login" element={<Login setUserRole={setUserRole} />} />

      {/* Dashboard berdasarkan role */}
      <Route
        path="/dashboard"
        element={
          isLoggedIn ? (
            userRole === 'Super Admin'
              ? <DashboardSuperAdmin />
              : <Dashboard role={userRole} />
          ) : (
            <Navigate to="/login" />
          )
        }
      />

      {/* Shared Routes (Admin & Super Admin) */}
      <Route
        path="/tracking"
        element={protectedRoute(<Tracking role={userRole} />, ['Admin', 'Super Admin'])}
      />
      <Route
        path="/info-driver"
        element={protectedRoute(<InfoDriver role={userRole} />, ['Admin', 'Super Admin'])}
      />
      <Route
        path="/settings"
        element={protectedRoute(<Settings role={userRole} />, ['Admin', 'Super Admin'])}
      />
      <Route
        path="/logout"
        element={<Logout setUserRole={setUserRole} />}
      />

      {/* Admin Only Route */}
      <Route
        path="/master-data"
        element={protectedRoute(<MasterData role={userRole} />, ['Admin'])}
      />

      {/* Super Admin Only Route */}
      <Route
        path="/bypass"
        element={protectedRoute(<ByPass role={userRole} />, ['Super Admin'])}
      />

      {/* Fallback */}
      <Route path="*" element={<Navigate to="/login" />} />
    </Routes>
  );
}
